import * as React from "react";

import { cn } from "@/lib/utils";

import "./skeleton.css";

type SkeletonProps = React.ComponentProps<"div"> & {
  visible?: boolean;
  animate?: boolean;
  inverted?: boolean;
  multiline?: boolean;
};

function Skeleton({
  className,
  children,
  visible = true,
  animate = true,
  inverted = false,
  multiline = false,
  ...props
}: SkeletonProps) {
  if (!visible && children) {
    return <>{children}</>;
  }

  const classes = cn(
    "bg-accent rounded-md",
    animate && [
      "skeleton-shimmer bg-fixed",
      inverted
        ? "bg-[linear-gradient(120deg,transparent_25%,oklch(0_0_0/15%)_50%,transparent_60%)]"
        : "bg-[linear-gradient(120deg,transparent_25%,oklch(1_0_0/75%)_50%,transparent_60%)]",
      "bg-size-[200%_100%]",
      inverted
        ? "dark:bg-[linear-gradient(120deg,transparent_25%,oklch(0_0_0/75%)_50%,transparent_60%)]"
        : "dark:bg-[linear-gradient(120deg,transparent_25%,oklch(1_0_0/15%)_50%,transparent_60%)]",
    ],
    className,
  );

  if (multiline) {
    return (
      <span
        data-slot="skeleton"
        className={cn(
          classes,
          "inline text-transparent [box-decoration-break:clone] [-webkit-box-decoration-break:clone]",
        )}
        {...(props as React.ComponentProps<"span">)}
      >
        {children}
      </span>
    );
  }

  return (
    <div
      data-slot="skeleton"
      className={cn(classes, children && "*:invisible")}
      {...props}
    >
      {children}
    </div>
  );
}
export { Skeleton };

/* -------------------------------------------------------------------------------------------------
 * Skeleton shimmer animation.
 *
 * Uses background-position-x on a static gradient (bg-size 200%) so the
 * browser can composite the shift instead of re-rasterizing the gradient
 * every frame. Combined with bg-fixed on the skeleton element, all skeletons
 * on the page sample the same viewport-aligned gradient and stay in phase.
 * -------------------------------------------------------------------------------------------------*/

.skeleton-shimmer {
  /* Negative animation-delay shifts the start phase so the sheen enters
     from the viewport's left edge at page load instead of sitting in the
     center. Matches the shadcn convention of -1s on 2s (half-cycle). */
  animation: shimmer 1.5s -0.75s linear infinite;
}

@keyframes shimmer {
  to {
    background-position-x: -200%;
  }
}
